"""
MKT Original Commentary — Joshua chapters 9–11
Run: python3 scripts/zc-original-joshua-9-11.py

Source data used:
- data/interlinear/joshua.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/joshua.json

Key decisions in this range:
- Josh 9:4 ʿormāh = 'cunning' (not 'shrewdly' — the word is morally neutral in Hebrew but here
  describes calculated deception; the same root describes the serpent in Gen 3:1)
- Josh 9:14 lōʾ shāʾalû ʾet-pî YHWH = 'they did not ask the mouth of YHWH' — the idiom means
  oracular inquiry (Urim/Thummim); the absence is the narrative's turning point
- Josh 10:12 dôm is rendered 'stand still/be silent' (as cosmic quietude, not mechanical stopping)
- Josh 11:20 ḥizzaq lēbābām = 'hardened their hearts' — same construction as Exodus Pharaoh
  passages; translated consistently with that usage
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

JOSHUA = {
  "9": {
    "1": "<p>The coalition of Canaanite kings is formulaic — <em>wayĕhî kišĕmōaʿ</em> ('when they heard') introduces a chain of reactions to Israel's advance. The geographic sweep ('hill country, western foothills, and along the entire coast') frames the total political landscape Israel now faces. The verb <em>wayyiqqāhălû</em> ('gathered/assembled') carries the sense of formal military muster, not spontaneous assembly.</p>",
    "2": "<p><em>ləlāḥam ʿim-yĕhôšuaʿ wĕʿim-yiśrāʾēl yāḥdāw</em> — 'to fight with Joshua and with Israel as one.' The adverb <em>yāḥdāw</em> (as one, together) signals the unprecedented solidarity of the Canaanite response; seven distinct peoples now act as a single force. The narrative's tension: will this coalition, unlike the Gibeonites, choose war over treaty?</p>",
    "3": "<p>The Gibeonites receive the same report the kings did (<em>wayišmĕʿû</em>) but respond differently. The contrast is deliberate: hearing the same news, one group forms a war coalition, another seeks survival through treaty. <em>ʿāśû gam-hēmmāh</em> — 'they also did' — introduces the alternative response with a particle of ironic echo.</p>",
    "4": "<p><em>wayyishtaddĕlû</em> — they acted, provisioned themselves cunningly. The key term is <em>ʿormāh</em> (v. 4's cognate <em>ʿārûm</em>), meaning cunning or craftiness. The same root describes the serpent in Gen 3:1 (<em>ʿārûm</em>); in Proverbs, cunning (<em>ʿormāh</em>) can be a virtue (Prov 8:5; 12:23) — wisdom applied strategically — but here it is deployed deceptively. The Gibeonites are clever; whether their cleverness is condemned depends on what Israel should have done at v.14.</p>",
    "5": "<p>The staging of deception is precise: worn sandals, patched, dry crumbling bread — each detail is verifiable at a glance. <em>niqqudîm</em> ('crumbly' or 'spotted' bread) is used only here and in 1 Sam 2:36 in a different sense; the bread's state signals great age. The Gibeonites have thought through every element of a convincing disguise.</p>",
    "6": "<p>They come to Joshua at Gilgal — Israel's base camp throughout the initial conquest phase (Josh 4:19; 5:10; 10:6). <em>ʾanašîm mērāḥôq bāʾnû</em> — 'men from a distant country we have come.' Their opening claim is the lie around which the entire chapter turns; the Hebrew word order puts 'from a distance' first, fronted for emphasis.</p>",
    "7": "<p><em>wayyōʾmĕrû ʾîš-yiśrāʾēl ʾel-haḥiwwî</em> — 'the men of Israel said to the Hivite.' The Hivites are specifically named — the narrative is already giving the reader information the Israelite leaders lack. Israel's question — 'perhaps you live among us' — reflects awareness of the <em>ḥērem</em> command: the nearby peoples must be destroyed (Deut 7:2; 20:17); treaties with them are forbidden (Deut 7:2). The question is therefore legally crucial, not merely polite.</p>",
    "8": "<p><em>ʿăbādêkā ʾănaḥnû</em> — 'your servants we are.' The idiom is diplomatic submission language, placing themselves under Joshua's protection. The question 'who are you and where do you come from?' follows diplomatic protocol for treaty negotiation. The Gibeonites' repeated use of 'servant' (<em>ʿebed</em>) throughout the chapter eventually shapes their permanent status at v.23.</p>",
    "9": "<p>The Gibeonites claim they came 'because of the name of YHWH your God' — a remarkable confession from Canaanites. They cite Sihon and Og (Num 21) but notably stop before mentioning Jericho and Ai — recent victories they had certainly heard about (v.3, <em>wayišmĕʿû</em>). This selective knowledge claim is part of the deception; they let Israel believe the Gibeonites are too remote to know the latest news.</p>",
    "10": "<p>The Gibeonites claim knowledge only of the trans-Jordan victories (Sihon and Og), implicitly denying knowledge of the Cisjordan campaigns. This is calculated omission — they knew (v.3) but pretend ignorance. <em>ʾašer ʿāśāh lĕšĕnê malkê hāʾĕmōrî</em> — 'what he did to the two kings of the Amorites': Sihon and Og were paradigmatic proof of YHWH's power (cited repeatedly in Deut and Ps 135-136), the minimum a distant nation might believably know.</p>",
    "11": "<p>The Gibeonites claim their elders and all inhabitants sent them. <em>kol-yōšĕbê ʾarṣênû</em> — 'all the inhabitants of our land' — they present themselves as official envoys, not individuals. The appeal to 'elders' (<em>zĕqēnîm</em>) establishes civic legitimacy, making the treaty a formal treaty with a people, not an ad hoc agreement.</p>",
    "12": "<p>The theatrical evidence: <em>zeh laḥmênû ḥam hillāʾnûhû</em> — 'this bread of ours was hot [when] we took it.' They present the physical props of deception, inviting Israel to examine the evidence and draw the wrong conclusion. The detail that the bread was 'our provision' (<em>ṣēdāh</em>) frames this as journey-supply, making the claim of distant origin seem verifiable.</p>",
    "13": "<p>Wineskins cracked from the journey, sandals worn out — the deception complete. The irony is that Israel is about to make a covenant based on evidence they handled but did not think to question spiritually (v.14). The Gibeonites provide exactly enough physical 'proof' to forestall skepticism.</p>",
    "14": "<p><em>wayyiqĕḥû hāʾănāšîm miṣṣēdām wĕʾet-pî YHWH lōʾ šāʾālû</em> — 'the men took from their provisions and the mouth of YHWH they did not ask.' This is the narrative's hinge. <em>šāʾal ʾet-pî YHWH</em> ('ask the mouth of YHWH') is the idiom for oracular inquiry via the high priest's Urim and Thummim (Num 27:21; 1 Sam 23:2). The phrase <em>lōʾ šāʾālû</em> ('they did not ask') indicts the leaders directly — they examined the physical evidence but skipped the theological check. The same verb root is embedded in the name 'Saul' (<em>Šāʾûl</em>, 'asked-for'), whose career is defined by the same failure.</p>",
    "15": "<p><em>wayyikrōt lāhem yĕhôšuaʿ šālôm wayyikrōt lāhem bĕrît</em> — 'Joshua cut peace with them and cut a covenant.' Both verbs are <em>kārat</em> (cut), the standard covenant-making idiom ('cut a covenant'), heightened here by double use. Once sworn before YHWH (<em>wayyiššābĕʿû lāhem nĕśîʾê hāʿēdāh</em>), the oath is binding — the leaders of the congregation have staked their word before God. The rest of the narrative turns on whether an oath made under deception remains binding; the answer is consistently yes (v.19-20).</p>",
    "16": "<p><em>miqṣēh šĕlōšet yāmîm</em> — 'at the end of three days.' Three days is significant: not immediately (which would excuse a hasty treaty), not years later, but a short enough interval that the leaders cannot claim ignorance was unavoidable. The cities are named: Gibeon, Chephirah, Beeroth, Kiriath-jearim — all in the territory of Benjamin, close to Jerusalem. The deceivers were neighbours.</p>",
    "17": "<p>The cities are Hivite (<em>ḥiwwî</em>), specifically listed, all within the central hill country. Their proximity to Jerusalem (Gibeon is ~9 km north) explains why their survival created long-term political tensions: these were not distant peoples but embedded enclaves in Israelite territory. The Benjaminite towns Beeroth and Kiriath-jearim figure in later narratives (the ark's resting places, 1 Sam 7:1; 2 Sam 6:2).</p>",
    "18": "<p><em>wayyillōnû kol-hāʿēdāh ʿal-hannĕśîʾîm</em> — 'all the congregation grumbled against the leaders.' The verb <em>lûn/lîn</em> (grumble, murmur) is the characteristic word for Israel's wilderness rebellion (Exod 15:24; 16:2; Num 14:2). The community's first instinct is violence — 'strike them down' — and the leaders' restraint preserves the oath's integrity over popular sentiment.</p>",
    "19": "<p><em>nišbaʿnû lāhem bYHWH ʾĕlōhê yiśrāʾēl</em> — 'we have sworn to them by YHWH the God of Israel.' The oath sworn in YHWH's name cannot be rescinded even though it was obtained by deception; violating it would be profaning YHWH's name. This becomes the foundation for Saul's later violation and the three-year famine (2 Sam 21:1-2): YHWH holds Israel to an oath sworn in his name regardless of how it was obtained.</p>",
    "20": "<p>The formula <em>wĕlōʾ yihyeh ʿālênû qeṣep</em> — 'lest wrath come upon us' — frames oath-violation as a theological risk: YHWH's <em>qeṣep</em> (wrath, burning anger) would fall on Israel, not the Gibeonites, if Israel broke the oath. The leaders understand the covenant structure: once sworn before YHWH, the commitment runs toward God, not just toward the Gibeonites.</p>",
    "21": "<p><em>yihyû ḥōṭĕbê ʿēṣîm wĕšōʾăbê mayim lĕkol-hāʿēdāh</em> — 'they will be woodcutters and water-carriers for all the congregation.' The permanent servile role preserves life within the covenant community. The phrase reappears at v.23 and v.27, where it is given a cultic dimension: service 'for the house of my God.' The Gibeonites are incorporated as a distinct service class — protected but not assimilated as equals.</p>",
    "22": "<p>Joshua's question is direct: <em>lāmmāh rimmîtĕm ʾōtānû</em> — 'why did you deceive us?' The verb <em>rāmāh</em> (deceive, betray) is strong, used of planned deception (Ps 78:57; Lam 1:19). Joshua does not nullify the treaty but demands an accounting; the covenant stands, its terms redrawn.</p>",
    "23": "<p><em>wĕʿattāh ʾărûrîm ʾattem</em> — 'and now cursed are you.' The <em>ʾārûr</em> formula is a formal covenant curse, not a personal imprecation. Yet the curse is immediately filled with specific content: perpetual servitude as woodcutters and water-carriers for 'the house of my God.' The curse is constructive — it assigns a permanent role within Israel's worship life. The Gibeonites are cursed into service, not cursed into destruction.</p>",
    "24": "<p>The Gibeonites' confession is remarkably candid: <em>kî hoggēd hoggad lāʿăbādêkā ʾēt ʾašer ṣiwwāh YHWH ʾĕlōhêkā ʾet-mōšeh ʾabdô</em> — 'because it was told to your servants what YHWH your God commanded his servant Moses.' They acted in self-preservation, knowing the <em>ḥērem</em> applied to them. Their fear was based on accurate theological knowledge: 'we were very afraid for our lives.'</p>",
    "25": "<p><em>wĕʿattāh hinnênû bĕyādekā kattôb wĕhayyāšār bĕʿênêkā laʿăśôt lānû ʿăśēh</em> — 'now we are in your hand; do to us as it is good and right in your eyes.' Total submission. The phrase <em>kattôb wĕhayyāšār</em> ('good and right') is a covenant-loyalty formula, appealing to Joshua's integrity. They are throwing themselves on his character.</p>",
    "26": "<p>Joshua rescues them (<em>wayyaṣṣēl ʾōtām</em>) — the same verb used of divine rescue throughout the OT. The irony: the Gibeonites deceived their way into the covenant, yet the covenant's protection functions exactly as promised — Israel cannot harm them, and Joshua actively defends them. In ch.10, this protection obligation will require a costly all-night military march.</p>",
    "27": "<p><em>wayyittēn ʾōtām yĕhôšuaʿ bayyôm hahûʾ ḥōṭĕbê ʿēṣîm wĕšōʾăbê mayim lāʿēdāh wĕlĕmizbaḥ YHWH</em> — assigned for 'the congregation and for the altar of YHWH, at whatever place he should choose.' The phrase <em>ʾel-hamāqôm ʾašer yibḥar</em> ('the place he will choose') is Deuteronomy's formula for the central sanctuary (Deut 12:5,11,14). The Gibeonites' future is tied to the future of Israelite worship — wherever the ark goes, they serve. This explains their presence at Nob (1 Sam 22:19) and their later connection to Gibeon's high place (1 Kgs 3:4).</p>"
  },
  "10": {
    "1": "<p>Adonizedek ('my lord is righteous') king of Jerusalem responds to Gibeon's treaty. <em>kî lāqaḥ yĕhôšuaʿ ʾet-hāgibʿôn wayyaḥărîmehā</em> — the king conflates Jericho's destruction with Gibeon's capitulation; from Jerusalem's perspective, both represent existential threats. The name Adonizedek echoes Melchizedek ('king of righteousness') from Gen 14:18 — a Jerusalem king whose name invokes righteousness now stands opposed to Israel.</p>",
    "2": "<p>Gibeon is described as 'like one of the royal cities, greater than Ai' — geographic and strategic context. <em>hî ʿîr gĕdôlāh kĕʾaḥat hāʿārîm hammamlākāh</em>: Gibeon's size and political status made its defection to Israel a seismic event. All its fighting men (<em>kol-ʾănāšêhā gibbōrîm</em>) had been Israel's potential adversaries; now they are treaty partners. Jerusalem's alarm is geopolitical, not merely religious.</p>",
    "3": "<p>The coalition of five Amorite kings — Jerusalem, Hebron, Jarmuth, Lachish, Eglon — represents a major southern military alliance. These cities controlled the Shephelah access routes; their cooperation signals coordinated Canaanite resistance to what they recognize as an existential threat. Adonizedek's role as initiator establishes Jerusalem as the political center of the resistance.</p>",
    "4": "<p><em>ʿălû ʾēlay wĕʿizerûnî wĕnakkeh ʾet-gibʿôn</em> — 'come up to me and help me, and let us strike Gibeon.' The military verb <em>nākāh</em> (strike down) is the same used of YHWH striking the Egyptians; punishing Gibeon is the coalition's immediate goal, but the deeper target is reversing the breach in the Canaanite defensive line.</p>",
    "5": "<p>The five kings encamp against Gibeon. The siege is the direct cause of the all-night march in v.9; Gibeon's treaty with Israel now triggers Israel's military obligation. YHWH's sovereignty is working through the coalition's aggression: by attacking Gibeon, they bring Israel's army to their doorstep.</p>",
    "6": "<p>Gibeon's appeal to Joshua is grounded in the treaty: <em>ʾal-terep yādêkā meʿăbādêkā</em> — 'do not relax your hand from your servants.' The phrase 'your servants' (<em>ʾăbādîm</em>) is the covenant-treaty language of ch.9; they invoke their status to claim Israel's military protection. The appeal is legally correct: the treaty obligates Israel to defend Gibeon.</p>",
    "7": "<p><em>wayyaʿal yĕhôšuaʿ min-haggillgāl hûʾ wĕkol-ʿam hammiḥāmāh ʿimmô</em> — 'Joshua went up from Gilgal, he and all the people of war with him.' The entire fighting force moves out; this is not a relief party but a full military campaign. The rapid response signals Joshua's seriousness about treaty obligations — he does not hesitate despite the deception that created the obligation.</p>",
    "8": "<p>YHWH's direct word of assurance: <em>ʾal-tîrāʾ mēhem kî bĕyādĕkā nĕtattîm</em> — 'do not fear them, for into your hand I have given them.' The perfect tense is prophetic: the victory is treated as already accomplished. This formula ('do not fear; I have given them') is the standard divine war oracle that inaugurates YHWH's battles (Deut 3:2; Josh 6:2; Judg 4:7).</p>",
    "9": "<p><em>wayyābōʾ ʾălêhem yĕhôšuaʿ pitʾōm kol-hallaylāh ʿālāh min-haggillgāl</em> — 'Joshua came upon them suddenly, having gone up all night from Gilgal.' The tactical detail is remarkable: a forced night march (~35 km, 1,000m elevation gain) to achieve surprise. <em>pitʾōm</em> ('suddenly') is the key tactical word; surprise was the advantage Israel's smaller force needed. The speed echoes YHWH's mode of operation: he comes suddenly, when not expected.</p>",
    "10": "<p><em>wayhummēm YHWH lifnê yiśrāʾēl</em> — 'YHWH threw them into confusion before Israel.' <em>Hûm/hāmam</em> is divine-panic vocabulary: the same verb YHWH used at the Red Sea (Exod 14:24) and will use in later battles (1 Sam 7:10). The 'great slaughter' at Gibeon gives way to pursuit; YHWH's confusion rout precedes human sword-work — the victory is his before it is Israel's.</p>",
    "11": "<p><em>wayyaṣṣēl YHWH ʾăbānîm gĕdōlôt min-haššāmayim ʿălêhem</em> — 'YHWH rained large stones from heaven upon them.' The hailstones are described as lethal divine artillery; <em>wayyāmutû rabbîm mēhem bĕʾabnê habbārād mēʾašer hēmîtû bĕnê yiśrāʾēl leḥāreb</em> — 'more died from the hailstones than Israel killed with the sword.' The divine contribution exceeds the human. The same combination — human army plus divine bombardment — recurs in the eschatological battles of Revelation (Rev 16:21: 100-lb hailstones).</p>",
    "12": "<p><em>ʾāz yĕdabbēr yĕhôšuaʿ lYHWH</em> — 'then Joshua spoke to YHWH.' What follows (v.12b-13) is a poetic quotation, set apart from the narrative. The address is to the sun and moon directly: <em>šemeš bĕgibʿôn dôm wĕyārēaḥ bĕʿēmeq ʾayyālôn</em> — 'Sun, in Gibeon, be silent/still; and moon, in the Valley of Aijalon.' The verb <em>dôm</em> (be still, be silent) is used of hushed awe before God (Ps 37:7; Hab 2:20); it may carry a sense of the cosmic realm falling silent before YHWH's battle-action, not merely of mechanical pause.</p>",
    "13": "<p><em>wayyiddōm haššemeš wĕyārēaḥ ʿāmād</em> — 'the sun stood still and the moon stopped.' The Hebrew verbs <em>dāmam</em> (be still) and <em>ʿāmad</em> (stood, halted) both describe cessation of motion. The duration: <em>kĕyôm tāmîm</em> — 'like a complete/perfect day.' The Book of Jashar (<em>sēper hayyāšār</em>, 'Book of the Upright') is cited as the source, a now-lost anthology also referenced in 2 Sam 1:18. The narrator invokes an external corroborating source for the most extraordinary claim in the chapter.</p>",
    "14": "<p><em>wĕlōʾ hāyāh kayyôm hahûʾ lĕpānāyw wĕʾaḥărāyw lišmōaʿ YHWH bĕqôl ʾîš</em> — 'there was no day like it before or since, in YHWH listening to the voice of a man.' The superlative formula ('never before or since') marks a unique event. The theological point: YHWH listened to a human voice and acted cosmically. <em>kî YHWH nilḥam lĕyiśrāʾēl</em> — 'for YHWH fought for Israel' — the divine warrior formula; this is YHWH's battle before it is Joshua's.</p>",
    "15": "<p><em>wayyāšob yĕhôšuaʿ wĕkol-yiśrāʾēl ʿimmô ʾel-hammaḥăneh haggillgālāh</em> — 'Joshua returned, all Israel with him, to the camp at Gilgal.' Text critics note this verse seems out of place — the five kings are still hiding (v.16-17) and the southern campaign continues through v.43. Some manuscripts (LXX) omit it here. The verse may be a dislocation or an editorial notice marking the end of the poetic insert.</p>",
    "16": "<p>The five kings flee and hide in a cave at Makkedah. <em>wayyimāsʾû nistarim bammĕʿārāh bĕmakkēdāh</em> — hiding in a cave mirrors the imagery of enemies cowering before YHWH's advance (Isa 2:19: 'men will enter caves... before the terror of YHWH'). Their capture and execution will become a teaching moment for Israel's commanders.</p>",
    "17": "<p>The cave is found and reported to Joshua. The rapid intelligence (<em>wayyuggad lĕyĕhôšuaʿ lēʾmōr</em>) and Joshua's immediate response demonstrate coordinated campaign management; the main pursuit continues while the cave is secured — priorities correctly ordered.</p>",
    "18": "<p><em>gōllû ʾăbānîm gĕdōlôt ʾel-pî hamĕʿārāh</em> — 'roll large stones to the mouth of the cave.' The stones serve dual purpose: prevent escape and mark the spot. The language of rolling stones into the mouth of a cave — sealing royalty inside — echoes in reverse in Gospel resurrection narratives (Mark 16:3; Matt 27:60).</p>",
    "19": "<p><em>wĕʾattem ʾal-taʿamĕdû raddĕpû ʾaḥărê ʾōyĕbêkem</em> — 'you, do not stand still; pursue after your enemies.' The imperative <em>rādap</em> (pursue) is urgent; half-measures in battle allow regroupment. The theological principle is embedded in the tactical instruction: YHWH has given them; do not leave the work half-done.</p>",
    "20": "<p>The slaughter is described as <em>ʿad-tummām mĕʾōd</em> — 'very great, until they were finished/consumed.' The remnant who survived reached their fortified cities. The two outcomes (total annihilation of those caught in the open; survival of those who reached fortified cities) explain why the south still required the mopping-up campaign of vv.28-43.</p>",
    "21": "<p><em>wayāšubû kol-hāʿām ʾel-hammaḥăneh ʾel-yĕhôšuaʿ bĕmakkēdāh bĕšālôm</em> — 'all the people returned safely to Joshua in the camp at Makkedah.' <em>Bĕšālôm</em> ('in peace/wholeness') marks the tactical return; no Israelite casualty is mentioned. <em>lōʾ ḥāraṣ lĕbĕnê yiśrāʾēl lĕʾîš ʾet-lĕšōnô</em> — 'not a man sharpened his tongue against Israel' — an idiom for hostile complaint or threat; the enemies are silenced.</p>",
    "22": "<p>Joshua commands the kings brought out. <em>pĕtĕḥû ʾet-pî hamĕʿārāh wĕhōṣîʾû ʾēlay ʾet-ḥamēšet hamĕlākîm</em> — 'open the mouth of the cave and bring out to me the five kings.' The verb <em>pāttaḥ</em> ('open the mouth') reverses the sealing of v.18; this is deliberate ceremony, not mere practicality.</p>",
    "23": "<p>The five kings are named again — Jerusalem, Hebron, Jarmuth, Lachish, Eglon. The geographic spread (north to south, hill country to Shephelah) encapsulates the southern region. Their naming here prepares for the teaching moment in v.24-25 and the subsequent campaign that conquers their cities individually (vv.28-39).</p>",
    "24": "<p><em>wayyiqrāʾ yĕhôšuaʿ ʾel-kol-ʾîš yiśrāʾēl wayyōʾmer ʾel-qĕṣînê ʾanšê hammiḥāmāh</em> — 'Joshua called all the men of Israel and said to the commanders.' The ritual of placing feet on the necks of defeated kings (<em>śîmû ʾet-raglêkem ʿal-ṣawwĕrê hammĕlākîm</em>) is documented in ANE victory iconography; Egyptian pharaohs and Assyrian kings are shown with feet on prostrate enemies. Paul applies the image to Christ in 1 Cor 15:25 ('until he has put all his enemies under his feet'; cf. Ps 110:1).</p>",
    "25": "<p><em>ʾal-tîrāʾû wĕʾal-tēḥāttû ḥizqû wĕʾimṣû</em> — 'do not be afraid and do not be dismayed; be strong and courageous.' This formula appears throughout Joshua (1:6,7,9; 10:25) and is explicitly God's word to Joshua in ch.1 — here Joshua passes it to his commanders. <em>kî-kāzōt yaʿăśeh YHWH lĕkol-ʾōyĕbêkem</em> — 'for this is what YHWH will do to all your enemies' — the military lesson is theological: the subjugated kings are a pledge of future victories, enacted by YHWH.</p>",
    "26": "<p><em>wayyakkēm yĕhôšuaʿ ʾaḥărê-kēn wayyĕmîtēm wayyitlēm ʿal ḥāmēšāh ʿēṣîm</em> — 'Joshua struck them, killed them, and hanged them on five trees.' Hanging on trees/poles was post-mortem humiliation (Deut 21:22-23) — it declared the executed person under God's curse (<em>qilĕlat ʾĕlōhîm tālûy</em>, Deut 21:23). Paul quotes this in Gal 3:13: 'Christ redeemed us from the curse of the law, having become a curse for us — for it is written, cursed is everyone who hangs on a tree.'</p>",
    "27": "<p>At sunset the bodies are removed and placed in the cave — the same cave that had been their hiding place. <em>wayyaggillû ʾăbānîm gĕdōlôt ʾal-pî hamĕʿārāh</em> — the stones seal the cave permanently; 'they are there to this day' (<em>ʿad-hayyôm hazzeh</em>) is an etiological formula marking a visible landmark. The cave becomes both grave and memorial.</p>",
    "28": "<p>The southern mopping-up campaign begins with Makkedah. <em>kĕkōl ʾašer ʿāśāh lĕmelek yĕrîḥô</em> — 'as he did to the king of Jericho.' The Jericho formula becomes the standard comparison for complete destruction (<em>ḥērem</em>); each city's destruction is measured against the paradigmatic first conquest. The refrain structures vv.28-39.</p>",
    "29": "<p>Israel moves to Libnah. The formulaic repetition ('then Joshua passed and all Israel with him') tracks the campaign's rapid tempo. Libnah will later figure in Isaiah's narrative of Sennacherib's campaign (Isa 37:8).</p>",
    "30": "<p>Libnah destroyed — king, inhabitants, all. The formula <em>lōʾ hiśʾîr bāh śārîd</em> ('he left no survivor') appears throughout the southern campaign. The LXX occasionally varies this formula; the MT is consistent. The refrain emphasizes totality, not body-count precision.</p>",
    "31": "<p>Lachish — strategically the most significant Shephelah fortress. Three days of siege (v.32) versus one-day victories elsewhere suggests genuine military resistance. Lachish's later prominence (Jer 34:7; 2 Kgs 14:19; the Lachish Letters) confirms its regional importance. Horam of Gezer comes to aid Lachish and is destroyed — relief forces are as futile as the besieged garrisons.</p>",
    "32": "<p><em>wayyitten YHWH ʾet-lākîš bĕyad yiśrāʾēl</em> — 'YHWH gave Lachish into Israel's hand.' The divine passive appears at each major victory; the narrative refuses to attribute conquest to military skill alone. The two-day timeline for Lachish (compared to one-day or all-at-once for others) may indicate a more formidable defense requiring full siege tactics.</p>",
    "33": "<p>Horam king of Gezer comes in relief. <em>wayyak ʾōtô yĕhôšuaʿ wĕʾet-ʿammô ʿad-bilti hišʾîr-lô śārîd</em> — 'Joshua struck him and his people until none remained.' The formula absorbs the relief force into the same annihilation refrain. Gezer itself will not be fully conquered (Josh 16:10; 1 Kgs 9:16) — an anticipation of the incomplete conquest acknowledged in ch.13.</p>",
    "34": "<p>Eglon taken in one day. The speed contrasts with Lachish's two-day siege; different cities present different levels of resistance. The campaign maintains momentum — no pauses for consolidation that might allow regroupment.</p>",
    "35": "<p>The Eglon formula: king, every person in it, all (<em>kol-nepeš</em>). <em>Nepeš</em> (soul/person/life) is used as 'every living person' in destruction formulas — it is not a theological claim about eternal souls but the standard Hebrew idiom for 'every inhabitant.'</p>",
    "36": "<p>Hebron — city of Abraham (Gen 13:18; 23:2), later David's first capital (2 Sam 2:1). Its capture here is temporary; it reverts (Josh 14:12-15; 15:13-14) as Caleb's allotted city. The formulaic destruction here and the later re-engagement with Hebron illustrate how the conquest summary in ch.10-11 is idealized: total victory is asserted even as subsequent chapters show it was partial.</p>",
    "37": "<p>Hebron: king, all its cities, all persons. The mention of 'all its cities' (<em>kol-ʿārêhā</em>) signals Hebron's regional control. The pattern of total destruction followed by resettlement (and eventual Canaanite persistence) is a recurring tension in the book.</p>",
    "38": "<p>Debir — mentioned in the conquest summary and later in Caleb's daughter's request (Josh 15:15-17; Judg 1:11-13). The repeated conquest tradition (here in ch.10; again in ch.15 via Othniel) reflects either variant traditions or a reconquest after Canaanite resettlement.</p>",
    "39": "<p>The Debir formula completes the southern sweep. <em>kĕkōl ʾašer ʿāśāh lĕḥebrôn</em> — 'as he had done to Hebron, so he did to Debir.' The southern campaign is complete; each city measured by the same standard of total destruction.</p>",
    "40": "<p><em>wayyak yĕhôšuaʿ ʾet-kol-hāʾāreṣ hāhār wĕhannegeb wĕhašŝĕpēlāh wĕhāʾăšēdôt</em> — 'Joshua struck all the land: the hill country, the Negev, the western foothills, and the slopes.' The geographic summary covers the complete southern zone. <em>kāʾăšer ṣiwwāh YHWH ʾĕlōhê yiśrāʾēl</em> — 'as YHWH God of Israel commanded' — the obedience formula anchors the destruction in divine mandate, not military ambition.</p>",
    "41": "<p>From Kadesh-barnea (the boundary of the wilderness) to Gaza (the coast) and from Goshen (not the Egyptian Goshen but a Negev region) to Gibeon — this is the full south-to-north extent of the southern campaign. The geographic markers frame the victory as comprehensive.</p>",
    "42": "<p><em>wĕʾet-kol-hamĕlākîm hāʾēlleh wĕʾet-ʾarṣām lāqaḥ yĕhôšuaʿ paʿam ʾeḥāt</em> — 'all these kings and their land Joshua took at one time.' <em>Paʿam ʾeḥāt</em> ('one time/one stroke') is emphatic — the rapidity of the campaign is a theological point: YHWH's hand moved swiftly. <em>kî YHWH ʾĕlōhê yiśrāʾēl nilḥam lĕyiśrāʾēl</em> — 'because YHWH the God of Israel fought for Israel.' The campaign's summary is theological before it is military.</p>",
    "43": "<p><em>wayyāšob yĕhôšuaʿ wĕkol-yiśrāʾēl ʿimmô ʾel-hammaḥăneh haggillgālāh</em> — 'Joshua returned, and all Israel with him, to the camp at Gilgal.' The return to base closes the southern campaign. Gilgal was Israel's cultic center and base of operations; the return marks the formal end of each campaign phase before the next begins (ch.11's northern campaign).</p>"
  },
  "11": {
    "1": "<p>Jabin king of Hazor triggers the northern coalition. Hazor is identified in v.10 as 'the head of all those kingdoms' — the dominant city-state of the north, confirmed by archaeology (Tell el-Qedah, the largest Bronze Age site in Canaan, ~200 acres). Jabin's name recurs in Judges 4 — either a dynastic name or a second Jabin after Israel's withdrawal. The name <em>yābîn</em> means 'he understands/discerns'; the name signals intelligence in the ruler, not just martial force.</p>",
    "2": "<p>The geographic spread — northern hill country, Arabah south of Kinnereth (Sea of Galilee), the western foothills, and the heights of Dor — covers the entire northern Levant. The campaign will be qualitatively different from the south: larger distances, different terrain, and a cavalry-heavy enemy (v.4).</p>",
    "3": "<p>The coalition includes Hivites (<em>ḥiwwî</em>, here specifically at Mizpah) — the same people group as the Gibeonites. The enumeration of peoples (Canaanites east/west, Amorites, Hittites, Perizzites, Jebusites) mirrors the standard Deuteronomy list (Deut 7:1) of the seven nations to be dispossessed. The totality of the opposition emphasizes YHWH's total victory.</p>",
    "4": "<p><em>wayyēṣĕʾû hēm wĕkol-maḥănêhem ʿimmāhem ʿam rab kaḥôl ʾašer ʿal-śĕpat hayyām lārōb</em> — 'they came out, they and all their forces with them, a vast people, as the sand on the shore of the sea.' The sand simile (<em>kaḥôl ʾašer ʿal-śĕpat hayyām</em>) is the standard biblical idiom for an uncountable multitude (Gen 22:17; Judg 7:12; 1 Sam 13:5). The force includes cavalry (<em>sûs wārekem</em>) and chariots — weaponry Israel lacks and has been told not to desire (v.6).</p>",
    "5": "<p>Assembly at the Waters of Merom — likely modern Meiron in Upper Galilee, a natural assembly point in the hill country. The coalition chooses defensible terrain; YHWH instructs a surprise attack (v.7) that neutralizes the positional advantage.</p>",
    "6": "<p><em>wayyōʾmer YHWH ʾel-yĕhôšuaʿ ʾal-tîrāʾ mippĕnêhem</em> — 'YHWH said to Joshua, do not fear them.' The reassurance is necessary because the northern coalition (chariots, horses, vast numbers) represents a military capability far beyond anything Israel has faced. The specific command: <em>ʾet-sûsêhem tĕʿaqqēr wĕʾet-merkĕbōtêhem tiśrōp bāʾēš</em> — 'you shall hamstring their horses and burn their chariots.' This deliberately deprives Israel of captured military technology; they must not build their security on horses and chariots (Ps 20:7; Deut 17:16). The command enforces dependence on YHWH rather than military parity.</p>",
    "7": "<p><em>wayyābōʾ yĕhôšuaʿ wĕkol-ʿam hammiḥāmāh ʿimmô ʾălêhem ʿal-mê mērôm pitʾōm</em> — 'Joshua and all the people of war with him fell upon them at the Waters of Merom suddenly.' <em>Pitʾōm</em> (suddenly) is the same tactical surprise used in ch.10:9. The surprise assault disrupts the enemy's formation before chariots and cavalry can be deployed — YHWH's strategy compensates for Israel's technological disadvantage.</p>",
    "8": "<p>YHWH gave them into Israel's hand (<em>wayyittēm YHWH bĕyad-yiśrāʾēl</em>). The divine passive precedes the tactical pursuit. The pursuit extends in four directions — Sidon (northwest coast), Misrephoth-maim (northern Phoenicia), the Valley of Mizpah (east) — showing that the coalition scattered in all directions, indicating a rout rather than a fighting retreat.</p>",
    "9": "<p><em>wayyaʿas lāhem yĕhôšuaʿ kaʾašer ʾāmar lô YHWH ʾet-sûsêhem ʿiqqēr wĕʾet-merkĕbōtêhem śārap bāʾēš</em> — 'Joshua did to them as YHWH had said: he hamstrung their horses and burned their chariots.' Exact obedience to the divine command, even when it meant destroying valuable military assets. The verse establishes the pattern for all of ch.11: YHWH commanded → Joshua obeyed completely (v.15: 'he left nothing undone').</p>",
    "10": "<p><em>wayyāšob yĕhôšuaʿ bāʿēt hahîʾ wayyilkōd ʾet-ḥāṣôr wayyak ʾet-malkāh beḥāreb</em> — 'Joshua turned at that time, captured Hazor, and struck its king with the sword.' Hazor is identified as <em>rōʾš kol-hammamlākôt hāhēnnāh</em> — 'head of all those kingdoms.' Its special destruction (burning, v.11) sets it apart from other northern cities; it is the northern equivalent of Jericho — the symbolic capital whose fall represents the collapse of the whole region.</p>",
    "11": "<p><em>wayyakû ʾet-kol-hannepeš ʾašer-bāh lĕpî-ḥereb haḥărēm ʾōtāh lōʾ niśʾar kol-nĕšāmāh</em> — 'they struck every person in it with the sword, devoting it to destruction; not a single living thing was left.' The <em>ḥērem</em> formula at full intensity; <em>nĕšāmāh</em> (breath/living thing) is used alongside <em>nepeš</em> (person) for emphasis. Hazor alone is burned (<em>wĕʾet-ḥāṣôr śārap bāʾēš</em>) — the same fate as Jericho (Josh 6:24), Ai (8:28), and the chariots (v.9). Archaeological layers at Tell el-Qedah confirm a major destruction in the Late Bronze Age.</p>",
    "12": "<p>All the cities of the northern kings were taken. <em>wayyak kol-malkām lĕpî-ḥereb haḥărēm ʾōtām</em> — 'he struck all their kings with the sword, devoting them to destruction.' The obedience formula: <em>kaʾašer ṣiwwāh mōšeh ʿebed YHWH</em> — 'as Moses the servant of YHWH had commanded.' The Mosaic mandate (Deut 7:1-5; 20:16-18) is the explicit grounding for the <em>ḥērem</em>; Joshua acts under Mosaic authority, not personal initiative.</p>",
    "13": "<p>Cities standing on their mounds (<em>ʿārîm hāʿōmĕdôt ʿal-tillām</em>) were not burned by Israel — only Hazor among the north is burned. This observation has archaeological significance: it explains why most northern sites show continuity layers rather than destruction layers in the relevant strata. The 'tells' (mound-cities) were preserved for Israelite habitation; only Hazor, as the symbolic capital, was destroyed.</p>",
    "14": "<p><em>wĕkol-šĕlal hehārîm hāʾēlleh wĕhabbĕhēmāh bāzĕzû lāhem bĕnê yiśrāʾēl</em> — 'all the spoil of these cities and the livestock, Israel plundered for themselves.' The distinction is explicit: livestock and goods may be taken, but the <em>ḥērem</em> applies to persons. This matches the Deuteronomic law (Deut 20:14) for distant cities, even though the northern campaign was against cities that fell under the total-destruction command.</p>",
    "15": "<p><em>kaʾašer ṣiwwāh YHWH ʾet-mōšeh ʿabdô kēn ṣiwwāh mōšeh ʾet-yĕhôšuaʿ wĕkēn ʿāśāh yĕhôšuaʿ lōʾ-hēsîr dābār mikkōl ʾašer-ṣiwwāh YHWH ʾet-mōšeh</em> — 'as YHWH commanded Moses his servant, so Moses commanded Joshua, and so Joshua did — he left nothing undone of all that YHWH commanded Moses.' This is the book's highest obedience formula: a three-link chain (YHWH→Moses→Joshua) with the explicit affirmation that nothing was omitted. This verse anchors the entire conquest as an act of covenantal obedience, not aggressive expansion.</p>",
    "16": "<p>The geographic summary of ch.11's conquest echoes the southern summary of ch.10:40-41, now extended north. The full schema: hill country, Negev, Goshen, the lowlands, the Arabah, hill country and foothills of Israel. The idealized totality ('all this land Joshua took') is the summary perspective; chs.13-19 will detail what remains.</p>",
    "17": "<p>From Mount Halak (southern boundary) to Baal-gad in the Lebanon Valley (northern boundary) — the full north-south axis of the Promised Land. The formula <em>kol-malkêhem lāqaḥ wayyakkēm wayyĕmîtēm</em> — 'he took all their kings, struck them, and put them to death' — applies to the entire campaign arc. The comprehensive victory claim is the narrator's theological assessment: YHWH gave what he promised.</p>",
    "18": "<p><em>yāmîm rabbîm ʿāśāh yĕhôšuaʿ ʾet-kol-hamĕlākîm hāʾēlleh miḥāmāh</em> — 'Joshua waged war against all these kings for a long time.' This verse is often overlooked but is crucial: the conquest was not rapid or magical. <em>Yāmîm rabbîm</em> ('many days') indicates years of ongoing warfare — archaeology supports a prolonged process, not a seven-year blitzkrieg. The theological point stands regardless: YHWH's faithfulness does not always mean immediate completion.</p>",
    "19": "<p><em>lōʾ hāyĕtāh ʿîr ʾašer hiśslîmāh ʾel-bĕnê yiśrāʾēl biltî haḥiwwî yōšĕbê gibʿôn</em> — 'there was not a city that made peace with Israel, except the Hivites who lived in Gibeon.' The Gibeonite exception is the only successful treaty; every other city chose war and faced destruction. The Gibeonites' survival is explicitly grounded in their unique decision for peace — a note that has canonical weight: the door was open, but only one people walked through it.</p>",
    "20": "<p><em>kî mēʾēt YHWH hāyĕtāh lĕḥazzēq ʾet-libbām liqraʾt hammiḥāmāh ʾet-yiśrāʾēl</em> — 'for it was from YHWH that it was to harden their hearts to meet Israel in war.' The <em>ḥizzēq</em> (harden) construction mirrors Exodus Pharaoh texts precisely: in Exodus, YHWH hardens Pharaoh's heart after Pharaoh first hardens his own; here the hardening is YHWH's initiative applied to the Canaanite kings. The purpose: <em>lemaʿan haḥărîmām</em> — 'in order to devote them to destruction.' The Canaanites' resistance is not presented as unfortunate obstruction but as divinely ordered — they chose war, and YHWH confirmed that choice so the judgment would be complete.</p>",
    "21": "<p>The Anakites (<em>ʿănāqîm</em>) — the giants who terrified the spies in Num 13:33 ('we seemed like grasshoppers to ourselves'). Their elimination from Israelite territory is presented as the resolution of Numbers' crisis: what the first generation feared and could not conquer, Joshua's generation destroys. The survivors are confined to Gaza, Gath, and Ashdod — Philistine cities. The Goliath of 1 Sam 17 (<em>gat</em>) is the Anakite remnant the next generation will face; David will finish what Joshua started.</p>",
    "22": "<p><em>lōʾ-nôtar ʿănāqîm bĕʾereṣ bĕnê yiśrāʾēl raq bĕʿazzāh bĕgat ûbĕʾašdôd niśʾārû</em> — 'no Anakites were left in Israelite territory; only in Gaza, Gath, and Ashdod did any remain.' The specificity of Gaza, Gath, Ashdod as Philistine cities is prospective: these are not just geographical notes but narrative setup for the Philistine conflicts and Goliath (1 Sam 17:4 — 'a Philistine... from Gath'). The seed of the next crisis is planted in the cleanup statement of the previous victory.</p>",
    "23": "<p><em>wayyiqqaḥ yĕhôšuaʿ ʾet-kol-hāʾāreṣ kĕkōl ʾašer dibber YHWH ʾel-mōšeh</em> — 'Joshua took the entire land, according to all that YHWH had spoken to Moses.' This verse closes both ch.11 and the conquest narrative (chs.1-11). Three affirmations: (1) the land was taken completely; (2) it matches YHWH's word to Moses (Gen 15:18-21 through Deut 34); (3) <em>wayyanhilāh lĕyiśrāʾēl kĕmahălĕqōtām lĕšibṭêhem</em> — 'he gave it as inheritance to Israel according to their tribal divisions.' The word <em>naḥălāh</em> (inheritance, portion, allotment) is the key term of the land theology; it implies permanent gift, not merely military conquest. <em>Wattišqōt hāʾāreṣ mimmilḥāmāh</em> — 'and the land had rest from war.' <em>Šāqaṭ</em> (rest, quietness) is the Deuteronomistic rest-formula (Deut 12:10); the land's rest is the partial fulfilment of the Sabbath-rest promised to Israel, which Hebrews 4:1-11 argues points toward a greater and permanent rest in Christ.</p>"
  }
}


def main():
    existing = load_comm('mkt-original', 'joshua')
    merge_comm(existing, JOSHUA)
    save_comm('mkt-original', 'joshua', existing)

    il = json.loads((ROOT / 'data/interlinear/joshua.json').read_text())
    all_ok = True
    for ch in range(9, 12):
        ck = str(ch)
        il_vv = set(il.get(ck, {}).keys())
        out_vv = set(existing.get(ck, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'ch {ch} MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All verses present ✓')


if __name__ == '__main__':
    main()
